from utils import slugify

def test_basic():
    assert slugify('Hello World') == 'hello-world'

def test_unicode():
    assert slugify('René Müller') == 'rene-muller'

def test_special_chars():
    assert slugify('Price: $100!') == 'price-100'

def test_consecutive_hyphens():
    assert slugify('one -- two') == 'one-two'

def test_leading_trailing():
    assert slugify('  spaces  ') == 'spaces'

def test_empty():
    assert slugify('') == ''

